pub fn print_table(records: &[Record], headers: &[String]) {
    let widths = headers
        .iter()
        .map(|h| {
            let max_value = records
                .iter()
                .filter_map(|r| r.fields.get(h))
                .map(|v| v.len())
                .max()
                .unwrap_or(0);
            h.len().max(max_value)
        })
        .collect::<Vec<_>>();

    let sep = widths
        .iter()
        .map(|w| "-".repeat(*w + 2))
        .collect::<Vec<_>>()
        .join("+");

    println!("{}", sep);
    for (i, h) in headers.iter().enumerate() {
        print!(" {:width$} ", h, width = widths[i]);
        if i + 1 != headers.len() {
            print!("|");
        }
    }
    println!();
    println!("{}", sep);

    for rec in records {
        for (i, h) in headers.iter().enumerate() {
            let v = rec.fields.get(h).cloned().unwrap_or_default();
            print!(" {:width$} ", v, width = widths[i]);
            if i + 1 != headers.len() {
                print!("|");
            }
        }
        println!();
    }
}

pub fn print_markdown_table(records: &[Record], headers: &[String]) {
    print!("|");
    for h in headers {
        print!(" {} |", h);
    }
    println!();

    print!("|");
    for _ in headers {
        print!("---|");
    }
    println!();

    for rec in records {
        print!("|");
        for h in headers {
            let v = rec.fields.get(h).cloned().unwrap_or_default();
            print!(" {} |", v);
        }
        println!();
    }
}

pub fn print_json(records: &[Record]) -> Result<(), AppError> {
    let stdout = io::stdout();
    let writer = BufWriter::new(stdout.lock());
    serde_json::to_writer_pretty(writer, records)?;
    Ok(())
}

pub fn print_csv(records: &[Record], headers: &[String]) -> Result<(), AppError> {
    let stdout = io::stdout();
    let mut wtr = csv::Writer::from_writer(BufWriter::new(stdout.lock()));
    wtr.write_record(headers)?;
    for rec in records {
        let row = headers
            .iter()
            .map(|h| rec.fields.get(h).cloned().unwrap_or_default())
            .collect::<Vec<_>>();
        wtr.write_record(row)?;
    }
    wtr.flush()?;
    Ok(())
}
